// // This D flip-flop captures the value of the input 'd' on the positive edge of the clock signal 'clk'. The output 'q' reflects the value of 'd' immediately before the clock transition.
module top_module(d,q,clk,rst);input d,clk,rst;
output reg q;

always@(negedge clk )
begin
    q=d;
 end

endmodule
